    quiz: [{"question": "The Coulter principle of cell counting is based on:", "options": ["Light scatter measurement", "Electrical impedance — cells displace electrolyte as they pass through an aperture causing measurable voltage changes proportional to cell volume", "Fluorescent staining intensity", "Centrifugal separation"], "correctIndex": 1, "rationale": "Coulter principle: cells suspended in conductive diluent pass through a small aperture between electrodes. Each cell displaces its volume of electrolyte, causing a voltage pulse proportional to cell size. Number of pulses = cell count; pulse height = cell volume."}]
